const state = JSON.parse(JSON.stringify($('Save Client Message').first().json));
const judgeNode = $('Judge Agent').first().json;

// дефолты
state.turn_count = Number(state.turn_count || 0);
state.max_turns = Number(state.max_turns || 10);

state.decision_result = false;
state.decision_text = "";
state.stop = false;
state.stop_reason = "";

// 1. сначала решение Judge Agent
let verdict = null;
let raw = judgeNode.output || "";

if (typeof raw === "string") {
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      verdict = JSON.parse(match[0]);
    } catch (e) {
      verdict = null;
    }
  }
} else if (typeof raw === "object" && raw !== null) {
  verdict = raw;
}

if (verdict && verdict.stop === true) {
  state.stop = true;
  state.stop_reason = verdict.reason || "judge_stopped";

  if (verdict.reason === "booking_confirmed") {
    state.decision_result = true;
    state.decision_text = "booking_confirmed";
  } else {
    state.decision_result = false;
    state.decision_text = verdict.reason || "";
  }

  return [{ json: state }];
}

// 2. потом лимит циклов
if (state.turn_count >= state.max_turns) {
  state.decision_result = false;
  state.decision_text = "max_turns_reached";
  state.stop = true;
  state.stop_reason = "max_turns_reached";

  return [{ json: state }];
}

// 3. продолжаем цикл
return [{ json: state }];

let prev;

try {
  prev = $('Parse Judge Result').first().json;
} catch (e) {
  prev = $('Edit Fields').first().json;
}

const admin = $('AI Agent').first().json;
const state = JSON.parse(JSON.stringify(prev));

state.turn_count = Number(state.turn_count || 0);
state.max_turns = Number(state.max_turns || 10);
state.conversation_as_text = state.conversation_as_text || "";
state.stop = false;
state.stop_reason = "";

const adminText = (admin.output || "").trim();

state.last_admin_message = adminText;
state.conversation_as_text =
  state.conversation_as_text +
  (state.conversation_as_text ? "\n\n" : "") +
  "Администратор: " + adminText;

return [{ json: state }];

const prev = $('Save Admin Message').first().json;
const client = $('AI Agent1').first().json;

const state = JSON.parse(JSON.stringify(prev));

state.turn_count = Number(state.turn_count || 0);
state.max_turns = Number(state.max_turns || 10);
state.conversation_as_text = state.conversation_as_text || "";

const clientText = (client.output || "").trim();

state.turn_count += 1;
state.last_client_message = clientText;
state.conversation_as_text =
  state.conversation_as_text +
  (state.conversation_as_text ? "\n\n" : "") +
  "Клиент: " + clientText;

return [{ json: state }];
